if (! function_exists('file_renamer')) {
    function file_renamer($path, $pattern = null, $replacement = null, $mode = null, $extension = null, $preview = null, $max_files = null, $dry_run = null)
    {
        // Batch file renamer - pattern-based renaming with preview
        $path=isset($path)?(string)$path:'';
        $pattern=isset($pattern)?(string)$pattern:'';
        $replacement=isset($replacement)?(string)$replacement:'';
        $mode=isset($mode)?(string)$mode:'replace';
        $ext_filter=isset($extension)?(string)$extension:'';
        $preview=isset($preview)?(bool)$preview:(isset($dry_run)?(bool)$dry_run:true);
        $max_files=isset($max_files)?min(max((int)$max_files,1),500):50;

        if($path==='')return['error'=>'Path required'];

        $full=realpath($path);
        if(!$full){$pr=realpath(__DIR__.'/../../..');$full=realpath($pr.'/'.$path);}
        if(!$full||!is_dir($full))return['error'=>"Dir not found: {$path}"];

        $files=[];
        $di=new RecursiveDirectoryIterator($full,RecursiveDirectoryIterator::SKIP_DOTS);
        foreach(new RecursiveIteratorIterator($di)as$item){
            if(!$item->isFile()||count($files)>=$max_files)continue;
            $bn=$item->getBasename();
            if($ext_filter!==''&&$item->getExtension()!==$ext_filter)continue;
            $files[]=['old_path'=>$item->getRealPath(),'old_name'=>$bn,'dir'=>dirname($item->getRealPath())];
        }

        if(count($files)===0)return['error'=>'No matching files found'];

        $renames=[];
        $errors=[];
        $to_rename=0;

        foreach($files as$f){
            $old=$f['old_name'];
            $new=$old;
            
            switch($mode){
                case 'replace':
                    if($pattern!=='')$new=str_replace($pattern,$replacement,$old);
                    break;
                case 'prefix':
                    $new=$pattern.$old;
                    break;
                case 'suffix':
                    $ext='';$base=$old;
                    $dot=strrpos($old,'.');
                    if($dot!==false){$ext=substr($old,$dot);$base=substr($old,0,$dot);}
                    $new=$base.$pattern.$ext;
                    break;
                case 'lowercase':
                    $new=strtolower($old);
                    break;
                case 'uppercase':
                    $new=strtoupper($old);
                    break;
                case 'regex':
                    if($pattern!=='')$new=preg_replace('/'.$pattern.'/',$replacement,$old);
                    break;
                default:
                    $errors[]="Unknown mode: {$mode}";
                    continue 2;
            }
            
            if($new===$old)continue;
            $new_path=$f['dir'].DIRECTORY_SEPARATOR.$new;
            $renames[]=['old_name'=>$old,'new_name'=>$new,'old_path'=>$f['old_path'],'new_path'=>$new_path];
            $to_rename++;
        }

        if(!$preview){
            $renamed=0;$failures=0;
            foreach($renames as$r){
                if(@rename($r['old_path'],$r['new_path']))$renamed++;
                else $failures++;
            }
            return['success'=>$renamed>0,'mode'=>$mode,'path'=>$path,'preview'=>false,'renamed'=>$renamed,'failures'=>$failures,'changes'=>$renames,'errors'=>$errors?:null];
        }

        return['success'=>true,'mode'=>$mode,'path'=>$path,'preview'=>true,'would_rename'=>$to_rename,'files_scanned'=>count($files),'changes'=>$renames,'errors'=>$errors?:null];
    }
